#include <iostream>
#include <iomanip>
#include <sstream>

class Vector2D {
private:
    double x;
    double y;

public:
    Vector2D(double x_val = 0.0, double y_val = 0.0) : x(x_val), y(y_val) {}

    Vector2D operator+(const Vector2D& other) {
        this->x += other.x;
        this->y += other.y;
        return *this;
    }

    friend std::ostream& operator<<(std::ostream& os, const Vector2D& v);
};

std::ostream& operator<<(std::ostream& os, const Vector2D& v) {
    os << "(" << v.x << ", " << v.y << ")";
    return os;
}

int main() {
    std::stringstream ss;
    ss << std::fixed << std::setprecision(1);

    Vector2D v1(1.0, 2.0);
    Vector2D v2(3.0, 4.0);
    Vector2D v3 = v1 + v2;
    ss << v3 << std::endl;
    ss << v1 << std::endl;

    Vector2D v_neg1(-1.0, 2.5);
    Vector2D v_neg2(3.5, -4.0);
    Vector2D v_neg_res = v_neg1 + v_neg2;
    ss << v_neg_res << std::endl;
    ss << v_neg1 << std::endl;

    Vector2D v_chain1(1.0, 1.0);
    Vector2D v_chain2(2.0, 2.0);
    Vector2D v_chain3(3.0, 3.0);
    Vector2D v_chain_res = v_chain1 + v_chain2 + v_chain3;
    ss << v_chain_res << std::endl;
    ss << v_chain1 << std::endl;

    Vector2D v_zero(0.0, 0.0);
    Vector2D v_nonzero(5.0, 6.0);
    Vector2D v_zero_res = v_zero + v_nonzero;
    ss << v_zero_res << std::endl;
    ss << v_zero << std::endl;

    std::cout << ss.str();
    return 0;
}
